<template>
    <Interface
        title="Dados de temperatura" btnLabel="Atualizar" btnIcon="refresh" btnAsEvent noHeader @action="update"
    >
        <Line style="width: 100%; height: 55vh" :data="temps" :options="options" />
    </Interface>
</template>

<script>
import { useDataStore } from '../stores/data.js'
import { Chart as ChartJS, CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend } from 'chart.js'
import { Line } from 'vue-chartjs'
import Interface from '../components/Interface.vue'

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend)

const dateFormat = (date) => new Date(new Date(date) - new Date().getTimezoneOffset() * 60000)
  .toISOString()
  .replace(/-/g, '/').replace('T', ' - ')
  .replace('Z', '').slice(0, -4)
  .split(' - ')[1] // just time

const options = {
  responsive: false,
  maintainAspectRatio: false
}

export default {
  name: 'Home',
  components: { Line, Interface },
  setup () {
    return { dataStore: useDataStore(), options }
  },
  data: () => ({
    // ...
  }),
  computed: {
    temps () {
      return {
        labels: (this.dataStore?.temps || []).map(v => dateFormat(v.date)),
        datasets: [
          {
            label: 'Temperatura',
            backgroundColor: '#f87979',
            borderColor: 'rgba(75, 192, 192, 1)',
            borderWidth: 1,
            data: (this.dataStore?.temps || []).map(v => v.temp)
          }
        ]
      }
    }
  },
  methods: {
    update () {
      this.dataStore.loadData(this.$api)
    }
  }
}
</script>
